
CREATE   PROCEDURE METRAPQ.usp_Merge_QuoteRilevate
AS
BEGIN
    SET NOCOUNT ON;

    MERGE INTO METRAPQ.QuoteRilevate AS TGT
    USING METRAPQ.QuoteRilevateView AS SRC ON (
         SRC.N = TGT.N 
    )

    WHEN MATCHED AND SRC.ChangeHashKey <> TGT.ChangeHashKey
      THEN UPDATE SET TGT.ChangeHashKey = SRC.ChangeHashKey, TGT.UpdateDatetime = SRC.UpdateDatetime, TGT.IsDeleted = SRC.IsDeleted, 
        TGT.DataCollaudo = SRC.DataCollaudo, TGT.IDClassificazioneProdotto = SRC.IDClassificazioneProdotto, TGT.ClassificazioneProdottoImpostata = SRC.ClassificazioneProdottoImpostata, TGT.NumeroLotto = SRC.NumeroLotto, TGT.InserimentoManuale = SRC.InserimentoManuale, TGT.Cliente = SRC.Cliente, TGT.RiferimentoCliente = SRC.RiferimentoCliente, TGT.CodiceCliente = SRC.CodiceCliente, TGT.Campionatura = SRC.Campionatura, TGT.CampionaturaTipo = SRC.CampionaturaTipo, TGT.Pressa = SRC.Pressa, TGT.OperatoreCollaudo = SRC.OperatoreCollaudo, TGT.Quantometro = SRC.Quantometro, TGT.AspettoSuperficiale = SRC.AspettoSuperficiale, TGT.PesoTeorico = SRC.PesoTeorico, TGT.PesoCalcolato = SRC.PesoCalcolato, TGT.Peso = SRC.Peso, TGT.CodiceMetra = SRC.CodiceMetra, TGT.BarraMatrice = SRC.BarraMatrice, TGT.DataEstrusione = SRC.DataEstrusione, TGT.Rugosimetro = SRC.Rugosimetro, TGT.Calibro = SRC.Calibro, TGT.MacchinaDiMisura = SRC.MacchinaDiMisura, TGT.Rotondimetro = SRC.Rotondimetro, TGT.MotivoNonConformita = SRC.MotivoNonConformita, TGT.etichettaMotivoNonConformita = SRC.etichettaMotivoNonConformita, TGT.Rullare = SRC.Rullare, TGT.Rullato = SRC.Rullato, TGT.Scartare = SRC.Scartare, TGT.RipetereTT = SRC.RipetereTT, TGT.SelezionareRicontrollare = SRC.SelezionareRicontrollare, TGT.AccettatoInDeroga = SRC.AccettatoInDeroga, TGT.Altro = SRC.Altro, TGT.ControlloImballoEseguito = SRC.ControlloImballoEseguito, TGT.DecisioniPreseAzioniCorrettive = SRC.DecisioniPreseAzioniCorrettive, TGT.EsitoRilavorazione = SRC.EsitoRilavorazione, TGT.Conformità = SRC.Conformità, TGT.FirmaRilavorazione = SRC.FirmaRilavorazione, TGT.ControllatoDa = SRC.ControllatoDa, TGT.IdoneoAllaSpedizione = SRC.IdoneoAllaSpedizione, TGT.IdoneoControlloCliente = SRC.IdoneoControlloCliente, TGT.DataSvincolo = SRC.DataSvincolo, TGT.CollaudoCliente = SRC.CollaudoCliente, TGT.BilletteDaEstrudere = SRC.BilletteDaEstrudere, TGT.BilletteEstruse = SRC.BilletteEstruse, TGT.Eliminata = SRC.Eliminata, TGT.Riconciliato = SRC.Riconciliato, TGT.EstrusioneEsterna = SRC.EstrusioneEsterna, TGT.EstrusioneEsternaNumeroDDT = SRC.EstrusioneEsternaNumeroDDT, TGT.EstrusioneEsternaDataDDT = SRC.EstrusioneEsternaDataDDT, TGT.EstrusioneEsternaFornitore = SRC.EstrusioneEsternaFornitore, TGT.CaratteristicheMeccanicheNonConformi = SRC.CaratteristicheMeccanicheNonConformi, TGT.LegaPredefinita = SRC.LegaPredefinita, TGT.LegaPredefinita_IDClassificazioneCaratteristiche = SRC.LegaPredefinita_IDClassificazioneCaratteristiche, TGT.StatoFisicoPredefinito = SRC.StatoFisicoPredefinito, TGT.StatoFisicoPredefinito_IDClassificazioneCaratteristiche = SRC.StatoFisicoPredefinito_IDClassificazioneCaratteristiche, TGT.DurezzaMaxRichiesta = SRC.DurezzaMaxRichiesta, TGT.DurezzaMaxRichiesta_IDClassificazioneCaratteristiche = SRC.DurezzaMaxRichiesta_IDClassificazioneCaratteristiche, TGT.DurezzaMinRichiesta = SRC.DurezzaMinRichiesta, TGT.DurezzaMinRichiesta_IDClassificazioneCaratteristiche = SRC.DurezzaMinRichiesta_IDClassificazioneCaratteristiche, TGT.RMRichiesto = SRC.RMRichiesto, TGT.RmRichiesto_IDClassificazioneCaratteristiche = SRC.RmRichiesto_IDClassificazioneCaratteristiche, TGT.RPRichiesto = SRC.RPRichiesto, TGT.RpRichiesto_IDClassificazioneCaratteristiche = SRC.RpRichiesto_IDClassificazioneCaratteristiche, TGT.ARichiesto = SRC.ARichiesto, TGT.ARichiesto_IDClassificazioneCaratteristiche = SRC.ARichiesto_IDClassificazioneCaratteristiche, TGT.ARichiestoTipo = SRC.ARichiestoTipo, TGT.RARichiesto = SRC.RARichiesto, TGT.RaRichiesto_IDClassificazioneCaratteristiche = SRC.RaRichiesto_IDClassificazioneCaratteristiche, TGT.RTRichiesto = SRC.RTRichiesto, TGT.RtRichiesto_IDClassificazioneCaratteristiche = SRC.RtRichiesto_IDClassificazioneCaratteristiche, TGT.RZRichiesto = SRC.RZRichiesto, TGT.RzRichiesto_IDClassificazioneCaratteristiche = SRC.RzRichiesto_IDClassificazioneCaratteristiche, TGT.RMaxRichiesto = SRC.RMaxRichiesto, TGT.RmaxRichiesto_IDClassificazioneCaratteristiche = SRC.RmaxRichiesto_IDClassificazioneCaratteristiche, TGT.Sistema = SRC.Sistema, TGT.SistemaID = SRC.SistemaID, TGT.Serie = SRC.Serie, TGT.SerieID = SRC.SerieID, TGT.Commessa = SRC.Commessa, TGT.NumeroCommessa = SRC.NumeroCommessa, TGT.ResponsabileAvvioProduzione = SRC.ResponsabileAvvioProduzione, TGT.OpportunitaNumero = SRC.OpportunitaNumero, TGT.OpportunitaDescrizione = SRC.OpportunitaDescrizione, TGT.OpportunitaIDSaleforce = SRC.OpportunitaIDSaleforce

    WHEN NOT MATCHED BY TARGET
      THEN INSERT (N, HistoricalHashKey, ChangeHashKey, InsertDatetime, UpdateDatetime, IsDeleted, DataCollaudo, IDClassificazioneProdotto, ClassificazioneProdottoImpostata, NumeroLotto, InserimentoManuale, Cliente, RiferimentoCliente, CodiceCliente, Campionatura, CampionaturaTipo, Pressa, OperatoreCollaudo, Quantometro, AspettoSuperficiale, PesoTeorico, PesoCalcolato, Peso, CodiceMetra, BarraMatrice, DataEstrusione, Rugosimetro, Calibro, MacchinaDiMisura, Rotondimetro, MotivoNonConformita, etichettaMotivoNonConformita, Rullare, Rullato, Scartare, RipetereTT, SelezionareRicontrollare, AccettatoInDeroga, Altro, ControlloImballoEseguito, DecisioniPreseAzioniCorrettive, EsitoRilavorazione, Conformità, FirmaRilavorazione, ControllatoDa, IdoneoAllaSpedizione, IdoneoControlloCliente, DataSvincolo, CollaudoCliente, BilletteDaEstrudere, BilletteEstruse, Eliminata, Riconciliato, EstrusioneEsterna, EstrusioneEsternaNumeroDDT, EstrusioneEsternaDataDDT, EstrusioneEsternaFornitore, CaratteristicheMeccanicheNonConformi, LegaPredefinita, LegaPredefinita_IDClassificazioneCaratteristiche, StatoFisicoPredefinito, StatoFisicoPredefinito_IDClassificazioneCaratteristiche, DurezzaMaxRichiesta, DurezzaMaxRichiesta_IDClassificazioneCaratteristiche, DurezzaMinRichiesta, DurezzaMinRichiesta_IDClassificazioneCaratteristiche, RMRichiesto, RmRichiesto_IDClassificazioneCaratteristiche, RPRichiesto, RpRichiesto_IDClassificazioneCaratteristiche, ARichiesto, ARichiesto_IDClassificazioneCaratteristiche, ARichiestoTipo, RARichiesto, RaRichiesto_IDClassificazioneCaratteristiche, RTRichiesto, RtRichiesto_IDClassificazioneCaratteristiche, RZRichiesto, RzRichiesto_IDClassificazioneCaratteristiche, RMaxRichiesto, RmaxRichiesto_IDClassificazioneCaratteristiche, Sistema, SistemaID, Serie, SerieID, Commessa, NumeroCommessa, ResponsabileAvvioProduzione, OpportunitaNumero, OpportunitaDescrizione, OpportunitaIDSaleforce)
        VALUES (N, HistoricalHashKey, ChangeHashKey, InsertDatetime, UpdateDatetime, IsDeleted, DataCollaudo, IDClassificazioneProdotto, ClassificazioneProdottoImpostata, NumeroLotto, InserimentoManuale, Cliente, RiferimentoCliente, CodiceCliente, Campionatura, CampionaturaTipo, Pressa, OperatoreCollaudo, Quantometro, AspettoSuperficiale, PesoTeorico, PesoCalcolato, Peso, CodiceMetra, BarraMatrice, DataEstrusione, Rugosimetro, Calibro, MacchinaDiMisura, Rotondimetro, MotivoNonConformita, etichettaMotivoNonConformita, Rullare, Rullato, Scartare, RipetereTT, SelezionareRicontrollare, AccettatoInDeroga, Altro, ControlloImballoEseguito, DecisioniPreseAzioniCorrettive, EsitoRilavorazione, Conformità, FirmaRilavorazione, ControllatoDa, IdoneoAllaSpedizione, IdoneoControlloCliente, DataSvincolo, CollaudoCliente, BilletteDaEstrudere, BilletteEstruse, Eliminata, Riconciliato, EstrusioneEsterna, EstrusioneEsternaNumeroDDT, EstrusioneEsternaDataDDT, EstrusioneEsternaFornitore, CaratteristicheMeccanicheNonConformi, LegaPredefinita, LegaPredefinita_IDClassificazioneCaratteristiche, StatoFisicoPredefinito, StatoFisicoPredefinito_IDClassificazioneCaratteristiche, DurezzaMaxRichiesta, DurezzaMaxRichiesta_IDClassificazioneCaratteristiche, DurezzaMinRichiesta, DurezzaMinRichiesta_IDClassificazioneCaratteristiche, RMRichiesto, RmRichiesto_IDClassificazioneCaratteristiche, RPRichiesto, RpRichiesto_IDClassificazioneCaratteristiche, ARichiesto, ARichiesto_IDClassificazioneCaratteristiche, ARichiestoTipo, RARichiesto, RaRichiesto_IDClassificazioneCaratteristiche, RTRichiesto, RtRichiesto_IDClassificazioneCaratteristiche, RZRichiesto, RzRichiesto_IDClassificazioneCaratteristiche, RMaxRichiesto, RmaxRichiesto_IDClassificazioneCaratteristiche, Sistema, SistemaID, Serie, SerieID, Commessa, NumeroCommessa, ResponsabileAvvioProduzione, OpportunitaNumero, OpportunitaDescrizione, OpportunitaIDSaleforce)

    WHEN NOT MATCHED BY SOURCE AND TGT.IsDeleted = CAST(0 AS BIT)
      THEN UPDATE SET TGT.ChangeHashKey = CONVERT(VARBINARY(32), 0),
        TGT.UpdateDatetime = CURRENT_TIMESTAMP,
        TGT.IsDeleted = CAST(1 AS BIT)
    
    OUTPUT
        CURRENT_TIMESTAMP AS merge_datetime,
        CASE WHEN Inserted.IsDeleted = CAST(1 AS BIT) THEN N'DELETE' ELSE $action END AS merge_action,
        'METRAPQ.QuoteRilevate' AS full_olap_table_name,
         'N = ' + CAST(COALESCE(inserted.N, deleted.N) AS NVARCHAR) AS primary_key_description
    INTO audit.merge_log_details;

END
GO

